<?phprequire_once __DIR__ . '/config.php';// دالة لإنشاء توكن JWT لتسجيل الدخولfunction generate_jwt($payload) {    $header = json_encode(['typ' => 'JWT', 'alg' => 'HS256']);        // التوكن صالح لمدة 7 أيام    $payload['iat'] = time();    $payload['exp'] = time() + (86400 * 7);    // تشفير Base64 URL Safe    $base64UrlHeader = str_replace(['+', '/', '='], ['-', '_', ''], base64_encode($header));    $base64UrlPayload = str_replace(['+', '/', '='], ['-', '_', ''], base64_encode(json_encode($payload)));    // توقيع التوكن    $signature = hash_hmac('sha256', $base64UrlHeader . "." . $base64UrlPayload, JWT_SECRET, true);    $base64UrlSignature = str_replace(['+', '/', '='], ['-', '_', ''], base64_encode($signature));    return $base64UrlHeader . "." . $base64UrlPayload . "." . $base64UrlSignature;}